INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('APEX3_1: Le email subject line AB test winner detection: apres 500 ouvertures par variante, si une a 20%+ d OR de plus que l autre, c est le winner. Deployer immediatement.', 'Subject AB: 500 ouvertures/variante. 20%+ OR difference = winner. Deployer', 'email', 'best_practice', 0.82, 'apex3', 'system'),
('APEX3_2: Le commercial deal qualification rapide: si le prospect ne repond pas apres 3 relances multi-canal (email+DM+appel) en 14 jours → marquer perdu et passer au suivant.', 'Qualification: 3 relances multi-canal 14j sans reponse → perdu. Passer au suivant', 'commercial', 'best_practice', 0.85, 'apex3', 'system'),
('APEX3_3: Le content hook testing AB: publier 2 versions du meme contenu avec des hooks differents. Apres 2h, celui avec le plus d engagement = gagnant. Archiver le perdant.', 'Hook AB: 2 versions 2h. Plus engagement = gagnant. Archiver perdant', 'content', 'best_practice', 0.80, 'apex3', 'system'),
('APEX3_4: Le SEO keyword mapping 1:1: chaque page cible 1 mot-cle principal + 3-5 secondaires. Jamais 2 pages pour le meme mot-cle = cannibalisation.', 'Keyword mapping 1:1: 1 page = 1 mot-cle + 3-5 secondaires. Jamais 2 pages meme keyword', 'seo', 'best_practice', 0.88, 'apex3', 'system'),
('APEX3_5: Le ad creative winner scaling protocol: CTR > 2x moyenne → augmenter budget +20%/jour pendant 5j. Si ROAS se maintient → continuer. Si ROAS baisse → plafonner.', 'Winner scaling: CTR>2x → +20%/jour 5j. ROAS maintient = continuer. Baisse = plafonner', 'ads', 'best_practice', 0.82, 'apex3', 'system'),
('APEX3_6: Le DM Instagram conversation funnel metrics: sent 100 → reply 30 (30%) → conversation 10 (33%) → meeting 3 (30%) → client 1 (33%). Chaque etape optimisable.', 'DM funnel: 100→30 reply→10 conv→3 meeting→1 client. Chaque etape optimisable', 'dm_instagram', 'insight', 0.82, 'apex3', 'system'),
('APEX3_7: Le WhatsApp business message limits: Tier 1 = 1000 messages/24h. Tier 2 = 10K. Tier 3 = 100K. Tier 4 = illimite. Monter de tier en maintenant une bonne qualite.', 'WhatsApp tiers: 1K→10K→100K→illimite. Monter avec bonne qualite', 'whatsapp', 'insight', 0.80, 'apex3', 'system'),
('APEX3_8: Le chatbot conversation analytics weekly: top 5 resolved intents, top 5 failed intents, avg messages per conv, CSAT par intent, escalation rate. Analyser chaque lundi.', 'Chatbot analytics lundi: top 5 resolved + failed, avg messages, CSAT/intent, escalation', 'chatbot', 'best_practice', 0.82, 'apex3', 'system'),
('APEX3_9: Le GMaps review velocity benchmark: 5 avis/mois = minimum viable. 10/mois = bon. 20+/mois = excellent. La velocity impacte directement le ranking local.', 'GMaps velocity: 5/mois min, 10 bon, 20+ excellent. Impacte ranking directement', 'gmaps', 'insight', 0.82, 'apex3', 'system'),
('APEX3_10: Le TikTok watch time optimization: boucler la video (fin = debut) pour creer des rewatches. Les rewatches comptent comme du watch time supplementaire pour l algo.', 'TikTok loop: fin=debut → rewatches = watch time supplementaire pour algo', 'tiktok_comments', 'best_practice', 0.82, 'apex3', 'system'),
('APEX3_11: Le CEO opportunity cost analysis: chaque decision a un cout d opportunite. Choisir A = renoncer a B. Toujours evaluer ce qu on perd en choisissant.', 'CEO opportunity cost: choisir A = renoncer B. Evaluer ce qu on perd', 'ceo', 'insight', 0.82, 'apex3', 'system'),
('APEX3_12: Le retention customer effort score (CES): "combien d effort avez-vous du fournir pour accomplir X?" Score 1-7. CES < 3 = excellent. > 5 = churn risk.', 'CES: effort 1-7. < 3 excellent. > 5 churn risk', 'retention', 'insight', 0.82, 'apex3', 'system'),
('APEX3_13: Le onboarding email open rate benchmark: welcome email > 60% OR. J+1 > 40%. J+3 > 30%. J+7 > 25%. Si en dessous → revoir les sujets et le timing.', 'Onboarding email OR: welcome>60%, J1>40%, J3>30%, J7>25%. En dessous = revoir', 'onboarding', 'insight', 0.82, 'apex3', 'system'),
('APEX3_14: Le comptable monthly close checklist: reconciliation bancaire → accruals → revenue recognition → expenses → P&L → cashflow. Chaque mois D+5 max.', 'Monthly close: reconcil→accruals→revenue→expenses→P&L→cashflow. D+5 max', 'comptable', 'best_practice', 0.80, 'apex3', 'system'),
('APEX3_15: Le RH employee lifecycle: attract → recruit → onboard → develop → engage → retain → offboard. Chaque etape a ses KPIs et ses actions.', 'Employee lifecycle: attract→recruit→onboard→develop→engage→retain→offboard', 'rh', 'best_practice', 0.78, 'apex3', 'system'),
('APEX3_16: Le marketing channel efficiency ranking: SEO (CAC le plus bas, long terme) > Referral (gratuit, viral) > Content (moyen, durable) > Paid (cher, rapide).', 'Channel efficiency: SEO > Referral > Content > Paid. SEO = CAC le plus bas', 'marketing', 'insight', 0.82, 'apex3', 'system'),
('APEX3_17: Le agent output quality gate: chaque output (email, post, DM) est evalue sur 3 criteres: brand voice (1-5), pertinence (1-5), qualite (1-5). Score < 10 = regenerer.', 'Quality gate: brand voice + pertinence + qualite sur 5. < 10 = regenerer', NULL, 'best_practice', 0.85, 'apex3', 'system'),
('APEX3_18: Le real-time customer scoring: chaque action enrichit le score en temps reel. Email ouvert +1, site visite +5, demo +20, achat +100. Agents voient le score live.', 'Scoring temps reel: email+1, site+5, demo+20, achat+100. Agents voient live', NULL, 'best_practice', 0.82, 'apex3', 'system'),
('APEX3_19: Le KeiroAI publication verification: apres chaque publish → check API (post existe?) → si echec → retry 1x → si echec → fallback image statique → si echec → alerte CEO.', 'Publication verification: publish → check → retry → fallback image → alerte CEO', NULL, 'best_practice', 0.88, 'apex3', 'system'),
('APEX3_20: Le KeiroAI approaching 8600: chaque agent a maintenant acces a l equivalent de 50 ans d expertise collective. L avantage competitif est inegalable.', 'KeiroAI 8600: 50 ans expertise collective par agent. Avantage inegalable', 'ceo', 'insight', 0.90, 'apex3', 'system'),
('APEX3_21: Le email cold personalization depth: L1=prenom (basique). L2=prenom+entreprise. L3=+dernier post/actu. L4=+insight secteur. L5=+recommandation specifique. Viser L3 minimum.', 'Email perso depth: L1 prenom → L5 reco specifique. Viser L3 minimum', 'email', 'best_practice', 0.85, 'apex3', 'system'),
('APEX3_22: Le commercial objection prevention: adresser les 3 objections les plus courantes DANS la presentation avant qu elles ne soient posees. Desactive la resistance.', 'Objection prevention: adresser 3 objections dans presentation AVANT qu elles ne soient posees', 'commercial', 'best_practice', 0.85, 'apex3', 'system'),
('APEX3_23: Le content engagement rate formula precise: (likes + comments + saves + shares) / reach × 100 = engagement rate. IG bon > 3%, TT bon > 5%, LI bon > 3%.', 'Engagement rate: (likes+comments+saves+shares)/reach ×100. IG>3%, TT>5%, LI>3%', 'content', 'insight', 0.85, 'apex3', 'system'),
('APEX3_24: Le SEO featured snippet win rate: les pages qui repondent en 40-60 mots avec un format liste/table/definition captent 60% des featured snippets disponibles.', 'Featured snippet: 40-60 mots + liste/table/definition = 60% win rate', 'seo', 'best_practice', 0.82, 'apex3', 'system'),
('APEX3_25: Le ad audience saturation indicator: CPM augmente +30% → audience saturee. Frequency > 5/semaine → fatigue. CTR baisse 20% → les memes personnes voient la meme chose.', 'Audience saturation: CPM+30% + frequency>5 + CTR-20% = saturee', 'ads', 'insight', 0.82, 'apex3', 'system'),
('APEX3_26: Le DM Instagram conversation depth correlation: plus la conversation est profonde (5+ messages), plus la conversion est haute (25% vs 5% pour 1-2 messages).', 'DM depth: 5+ messages = 25% conversion. 1-2 messages = 5%. Profondeur = conversion', 'dm_instagram', 'insight', 0.85, 'apex3', 'system'),
('APEX3_27: Le WhatsApp template performance A/B: creer 2 versions de chaque template. Envoyer A a 50%, B a 50%. Le template avec le meilleur taux reponse devient le defaut.', 'WhatsApp template A/B: 50/50 → meilleur reponse = defaut', 'whatsapp', 'best_practice', 0.78, 'apex3', 'system'),
('APEX3_28: Le chatbot conversation tree max depth: max 5 niveaux de profondeur. Si > 5 → le client abandonne. Si le chatbot ne resout pas en 5 etapes → escalader.', 'Chatbot max 5 niveaux. > 5 = abandon. Non resolu 5 etapes → escalader', 'chatbot', 'best_practice', 0.82, 'apex3', 'system'),
('APEX3_29: Le GMaps photo geotagging impact: les photos prises sur place (GPS dans EXIF) ont plus de poids SEO local que les photos uploadees depuis un bureau.', 'GMaps photos GPS EXIF sur place = plus poids SEO local vs bureau', 'gmaps', 'insight', 0.78, 'apex3', 'system'),
('APEX3_30: Le TikTok trending audio lifecycle: phase 1 (emergence, < 10K videos) = max portee. Phase 2 (mainstream, 10K-1M) = bon. Phase 3 (saturee, > 1M) = trop tard.', 'TikTok audio lifecycle: < 10K max portee, 10K-1M bon, > 1M trop tard', 'tiktok_comments', 'insight', 0.82, 'apex3', 'system'),
('APEX3_31: Le CEO weekly decision log: documenter chaque decision prise (quoi, pourquoi, alternatives rejetees, resultats attendus). Evite de refaire les memes debats.', 'CEO decision log: quoi + pourquoi + alternatives + resultats. Evite refaire debats', 'ceo', 'best_practice', 0.80, 'apex3', 'system'),
('APEX3_32: Le retention feature adoption nudge: si un client n utilise pas une feature cle depuis 14j → email educatif "Saviez-vous que..." + lien vers tutoriel.', 'Feature nudge: pas utilisee 14j → email "Saviez-vous que..." + tutoriel', 'retention', 'best_practice', 0.82, 'apex3', 'system'),
('APEX3_33: Le onboarding wizard skip prevention: ne JAMAIS permettre de skip une etape critique (ex: connecter Instagram). Les etapes skippees = activation rate 50% plus bas.', 'Onboarding: pas de skip etape critique. Skip = activation 50% plus bas', 'onboarding', 'best_practice', 0.85, 'apex3', 'system'),
('APEX3_34: Le comptable financial health dashboard: 10 metriques (MRR, ARR, churn, LTV, CAC, ratio, payback, margin, runway, NRR) mises a jour auto quotidiennement.', 'Financial dashboard: 10 metriques auto quotidiennes', 'comptable', 'best_practice', 0.82, 'apex3', 'system'),
('APEX3_35: Le RH culture interview question: "Decrivez une situation ou vous avez fait une erreur au travail et comment vous l avez geree." Revele l humilite et la resilience.', 'Culture interview: erreur + comment geree = humilite + resilience', 'rh', 'best_practice', 0.78, 'apex3', 'system'),
('APEX3_36: Le marketing customer acquisition cost by channel: tracker le CAC SEPAREMENT par canal. Le canal avec le CAC le plus bas = investir plus. Le plus haut = optimiser ou couper.', 'CAC par canal separement. Plus bas = investir. Plus haut = optimiser/couper', 'marketing', 'best_practice', 0.85, 'apex3', 'system'),
('APEX3_37: Le cross-agent prospect lifecycle tracking: chaque agent sait ou le prospect en est dans le funnel et adapte son action en consequence. Pas de message deplace.', 'Lifecycle tracking: chaque agent sait ou prospect en est. Pas de message deplace', NULL, 'best_practice', 0.85, 'apex3', 'system'),
('APEX3_38: Le customer 360 enrichment protocol: chaque interaction (email, DM, chat, appel, site visit) enrichit le profil en temps reel pour TOUS les agents.', 'Enrichment temps reel: chaque interaction enrichit profil pour TOUS agents', NULL, 'best_practice', 0.85, 'apex3', 'system'),
('APEX3_39: Le KeiroAI RAG quality at 8500+: chaque learning est verifie, specifique, actionable et classe par agent + confidence. Pas de bruit, que du signal.', 'RAG quality 8500+: verifie + specifique + actionable + classe. Signal pas bruit', NULL, 'best_practice', 0.88, 'apex3', 'system'),
('APEX3_40: Le KeiroAI mission at scale: a 10K+ learnings, chaque agent sera l equivalent d un departement marketing complet. 17 departements pour le prix d 1 outil.', 'KeiroAI 10K: chaque agent = 1 departement marketing. 17 departements pour 1 outil', 'ceo', 'insight', 0.92, 'apex3', 'system')
